@@ -0,0 +1,80 @@
+package db
+
+import (
+	"strings"
+)
+
+type ResourceType int
+
+const (
+	TypeDatabase ResourceType = iota
+	TypeDocument
+	TypeCollection
+)
+
+type PathInfo struct {
+	Database       string
+	Segments       []string // Alternating doc/col names
+	ResourceType   ResourceType
+	IsCollection   bool // ends with /
+	CollectionPath []string // for convenience, all segments except the last if it's a doc
+}
+
+func ParsePath(path string) (*PathInfo, bool) {
+	// Path starts with /v1/
+	if !strings.HasPrefix(path, "/v1/") {
+		return nil, false
+	}
+	trimmed := strings.TrimPrefix(path, "/v1/")
+	if trimmed == "" {
+		return nil, false
+	}
+
+	isDir := strings.HasSuffix(trimmed, "/")
+	parts := strings.Split(strings.Trim(trimmed, "/"), "/")
+
+	if len(parts) == 0 || parts[0] == "" {
+		return nil, false
+	}
+
+	info := &PathInfo{
+		Database:     parts[0],
+		Segments:     parts[1:],
+		IsCollection: isDir,
+	}
+
+	// Determine ResourceType
+	if len(info.Segments) == 0 {
+		info.ResourceType = TypeDatabase
+		// We'll allow no trailing slash for databases for PUT/DELETE
+		// but instructions say they MUST have it. 
+		// "If the final element of the path is a database or collection, the path must end with a trailing slash."
+		// However, many tests and Swagger might use it without.
+	} else {
+		// Even number of segments means it ends with a document name if no trailing slash.
+		// Odd number of segments means it ends with a collection name if trailing slash.
+		// Example: /db/doc/col/ -> segments=["doc", "col"], isDir=true. ResourceType = TypeCollection
+		// Example: /db/doc -> segments=["doc"], isDir=false. ResourceType = TypeDocument
+		// Example: /db/doc/col/doc2 -> segments=["doc", "col", "doc2"], isDir=false. ResourceType = TypeDocument
+		
+		if len(info.Segments)%2 == 1 {
+			// doc, doc/col/doc, etc.
+			if isDir {
+				// /db/doc/ is invalid?
+				// "If the final element of the path is a document, the path must not have a trailing slash"
+				return nil, false
+			}
+			info.ResourceType = TypeDocument
+		} else {
+			// doc/col, doc/col/doc/col, etc.
+			if !isDir {
+				// /db/doc/col is invalid?
+				// "If the final element of the path is a database or collection, the path must end with a trailing slash"
+				return nil, false
+			}
+			info.ResourceType = TypeCollection
+		}
+	}
+
+	return info, true
+}
