+package server
+
+import (
+	"encoding/json"
+	"log/slog"
+	"net/http"
+	"strings"
+
+	"github.com/RICE-COMP318-FALL24/owldb-gemini/auth"
+	"github.com/RICE-COMP318-FALL24/owldb-gemini/db"
+	"github.com/santhosh-tekuri/jsonschema/v5"
+)
+
+type Server struct {
+	root      *db.Root
+	auth      *auth.AuthSystem
+	schema    *jsonschema.Schema
+	schemaURL string
+	sm        *SubscriptionManager
+}
+
+func NewServer(root *db.Root, auth *auth.AuthSystem, schema *jsonschema.Schema, schemaURL string) *Server {
+	return &Server{
+		root:      root,
+		auth:      auth,
+		schema:    schema,
+		schemaURL: schemaURL,
+		sm:        NewSubscriptionManager(),
+	}
+}
+
+func (s *Server) ServeHTTP(w http.ResponseWriter, r *http.Request) {
+	slog.Debug("Request", "method", r.Method, "path", r.URL.Path)
+
+	if r.URL.Path == "/auth" {
+		s.handleAuth(w, r)
+		return
+	}
+
+	if r.Method == http.MethodOptions {
+		s.handleOptions(w, r)
+		return
+	}
+
+	// All other requests require authentication
+	username, ok := s.authenticate(r)
+	if !ok {
+		s.errorResponse(w, http.StatusUnauthorized, "Missing or invalid bearer token")
+		return
+	}
+
+	if strings.HasPrefix(r.URL.Path, "/v1/") {
+		s.handleV1(w, r, username)
+		return
+	}
+
+	s.errorResponse(w, http.StatusNotFound, "Not found")
+}
+
+func (s *Server) authenticate(r *http.Request) (string, bool) {
+	authHeader := r.Header.Get("Authorization")
+	if !strings.HasPrefix(authHeader, "Bearer ") {
+		return "", false
+	}
+	token := strings.TrimPrefix(authHeader, "Bearer ")
+	return s.auth.Authenticate(token)
+}
+
+func (s *Server) handleAuth(w http.ResponseWriter, r *http.Request) {
+	if r.Method == http.MethodPost {
+		var body struct {
+			Username string `json:"username"`
+		}
+		if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
+			s.errorResponse(w, http.StatusBadRequest, "Invalid request body")
+			return
+		}
+		if body.Username == "" {
+			s.errorResponse(w, http.StatusBadRequest, "No username in request body")
+			return
+		}
+		token := s.auth.Login(body.Username)
+		jsonResponse(w, http.StatusOK, map[string]string{"token": token})
+		return
+	}
+
+	if r.Method == http.MethodDelete {
+		authHeader := r.Header.Get("Authorization")
+		if !strings.HasPrefix(authHeader, "Bearer ") {
+			s.errorResponse(w, http.StatusUnauthorized, "Missing or invalid bearer token")
+			return
+		}
+		token := strings.TrimPrefix(authHeader, "Bearer ")
+		if s.auth.Logout(token) {
+			w.WriteHeader(http.StatusNoContent)
+		} else {
+			s.errorResponse(w, http.StatusUnauthorized, "Missing or invalid bearer token")
+		}
+		return
+	}
+
+	s.errorResponse(w, http.StatusMethodNotAllowed, "Method not allowed")
+}
+
+func (s *Server) handleOptions(w http.ResponseWriter, r *http.Request) {
+	if r.URL.Path == "/auth" {
+		w.Header().Set("Allow", "POST, DELETE, OPTIONS")
+		w.WriteHeader(http.StatusNoContent)
+		return
+	}
+
+	pathInfo, ok := db.ParsePath(r.URL.Path)
+	if !ok {
+		w.WriteHeader(http.StatusNoContent)
+		return
+	}
+
+	switch pathInfo.ResourceType {
+	case db.TypeDatabase:
+		w.Header().Set("Allow", "GET, PUT, DELETE, POST, OPTIONS")
+	case db.TypeDocument:
+		w.Header().Set("Allow", "GET, PUT, PATCH, DELETE, OPTIONS")
+	case db.TypeCollection:
+		w.Header().Set("Allow", "GET, PUT, POST, DELETE, OPTIONS")
+	}
+	w.WriteHeader(http.StatusNoContent)
+}
+
+func (s *Server) errorResponse(w http.ResponseWriter, code int, message string) {
+	w.Header().Set("Content-Type", "application/json")
+	w.WriteHeader(code)
+	json.NewEncoder(w).Encode(map[string]string{"error": message})
+}
+
+func jsonResponse(w http.ResponseWriter, code int, data any) {
+	w.Header().Set("Content-Type", "application/json")
+	w.WriteHeader(code)
+	json.NewEncoder(w).Encode(data)
+}
